describe('calculateQuote', () => {
  it('empty rules', () => { const q = calculateQuote([], {}); expect(q.items).toHaveLength(0); expect(q.total).toBe(0); });
  it('zero qty excluded', () => { expect(calculateQuote([flatRule()], { r1: 0 }).items).toHaveLength(0); });
  it('GBP currency', () => { expect(calculateQuote([flatRule()], { r1: 1 }).currency).toBe('GBP'); });
  it('USD currency', () => { expect(calculateQuote([perUnitRule()], { r4: 1 }).currency).toBe('USD'); });
  it('totalTax agg', () => { const r = withTax(flatRule(), 20); const q = calculateQuote([r], { r1: 2 }); expect(q.totalTax).toBeCloseTo(80); });
  it('totalDiscount agg', () => { const r = withDiscount(flatRule(), { type: 'percentage', value: 10 }); const q = calculateQuote([r], { r1: 2 }); expect(q.totalDiscount).toBeCloseTo(40); });
  it('total=sub-disc+tax', () => { const r = withTax(withDiscount(flatRule(), { type: 'percentage', value: 10 }), 20); const q = calculateQuote([r], { r1: 3 }); expect(q.total).toBeCloseTo(q.subtotal - q.totalDiscount + q.totalTax); });
  it('missing qty excluded', () => { expect(calculateQuote([flatRule()], {}).items).toHaveLength(0); });
  it('flat qty=1 total=200', () => { expect(calculateQuote([flatRule()], { r1: 1 }).total).toBe(200); });
  it('flat qty=2 total=400', () => { expect(calculateQuote([flatRule()], { r1: 2 }).total).toBe(400); });
  it('flat qty=3 total=600', () => { expect(calculateQuote([flatRule()], { r1: 3 }).total).toBe(600); });
  it('flat qty=4 total=800', () => { expect(calculateQuote([flatRule()], { r1: 4 }).total).toBe(800); });
  it('flat qty=5 total=1000', () => { expect(calculateQuote([flatRule()], { r1: 5 }).total).toBe(1000); });
  it('flat qty=6 total=1200', () => { expect(calculateQuote([flatRule()], { r1: 6 }).total).toBe(1200); });
  it('flat qty=7 total=1400', () => { expect(calculateQuote([flatRule()], { r1: 7 }).total).toBe(1400); });
  it('flat qty=8 total=1600', () => { expect(calculateQuote([flatRule()], { r1: 8 }).total).toBe(1600); });
  it('flat qty=9 total=1800', () => { expect(calculateQuote([flatRule()], { r1: 9 }).total).toBe(1800); });
  it('flat qty=10 total=2000', () => { expect(calculateQuote([flatRule()], { r1: 10 }).total).toBe(2000); });
  it('flat qty=11 total=2200', () => { expect(calculateQuote([flatRule()], { r1: 11 }).total).toBe(2200); });
  it('flat qty=12 total=2400', () => { expect(calculateQuote([flatRule()], { r1: 12 }).total).toBe(2400); });
  it('two rules summed', () => { const q = calculateQuote([flatRule(), perUnitRule()], { r1: 2, r4: 3 }); expect(q.subtotal).toBeCloseTo(550); });
  it('zero price rule', () => { const r = makeRule('z','Z','flat',0); const q = calculateQuote([r], { z: 100 }); expect(q.total).toBe(0); });
  it('large qty 1M', () => { const r = makeRule('b','B','flat',1); const q = calculateQuote([r], { b: 1000000 }); expect(q.subtotal).toBe(1000000); });
  it('volume rule', () => { expect(calculateQuote([volumeRule()], { r2: 20 }).subtotal).toBe(1600); });
  it('full discount total=0', () => { const r = withDiscount(makeRule('f','F','flat',100), { type: 'fixed', value: 10000 }); const q = calculateQuote([r], { f: 1 }); expect(q.total).toBe(0); expect(q.totalDiscount).toBe(100); });
  it('ruleIds in items', () => { const q = calculateQuote([makeRule('al','Al','flat',100), makeRule('be','Be','flat',200)], { al: 1, be: 2 }); expect(q.items.map(i => i.ruleId)).toContain('al'); expect(q.items.map(i => i.ruleId)).toContain('be'); });
});

