  it('empty=>0', () => { const q: PriceQuote = { items: [], subtotal: 0, totalDiscount: 0, totalTax: 0, total: 0, currency: 'GBP' }; expect(totalItems(q)).toBe(0); });
  it('single qty=1', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 1 }))).toBe(1); });
  it('single qty=2', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 2 }))).toBe(2); });
