  it('single qty=10', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 10 }))).toBe(10); });
  it('single qty=11', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 11 }))).toBe(11); });
  it('single qty=12', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 12 }))).toBe(12); });
  it('single qty=13', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 13 }))).toBe(13); });
  it('single qty=14', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 14 }))).toBe(14); });
  it('single qty=15', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 15 }))).toBe(15); });
  it('single qty=16', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 16 }))).toBe(16); });
  it('single qty=17', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 17 }))).toBe(17); });
  it('single qty=18', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 18 }))).toBe(18); });
