  it('single qty=20', () => { expect(totalItems(calculateQuote([flatRule()], { r1: 20 }))).toBe(20); });
  it('1 items qty=5 => 5', () => { const rules: PriceRule[] = Array.from({ length: 1 }, (_,i) => makeRule('r'+i,'R','flat',10)); const qtys: Record<string, number> = {}; rules.forEach(r => { qtys[r.id] = 5; }); expect(totalItems(calculateQuote(rules, qtys))).toBe(5); });
  it('2 items qty=5 => 10', () => { const rules: PriceRule[] = Array.from({ length: 2 }, (_,i) => makeRule('r'+i,'R','flat',10)); const qtys: Record<string, number> = {}; rules.forEach(r => { qtys[r.id] = 5; }); expect(totalItems(calculateQuote(rules, qtys))).toBe(10); });
