  it('round(9.995,2)~9.99', () => { expect(roundPrice(9.995,2)).toBeCloseTo(9.99,2); });
  it('round(99.994,2)~99.99', () => { expect(roundPrice(99.994,2)).toBeCloseTo(99.99,2); });
  it('round(0.005,2)~0.01', () => { expect(roundPrice(0.005,2)).toBeCloseTo(0.01,2); });
  it('round(1000,0)~1000', () => { expect(roundPrice(1000,0)).toBeCloseTo(1000,0); });
  it('round(1234.5678,3)~1234.568', () => { expect(roundPrice(1234.5678,3)).toBeCloseTo(1234.568,3); });
  it('round(7.777,1)~7.8', () => { expect(roundPrice(7.777,1)).toBeCloseTo(7.8,1); });
  it('round(7.749,1)~7.7', () => { expect(roundPrice(7.749,1)).toBeCloseTo(7.7,1); });
  it('round(3.14159,2)~3.14', () => { expect(roundPrice(3.14159,2)).toBeCloseTo(3.14,2); });
  it('round(2.71828,3)~2.718', () => { expect(roundPrice(2.71828,3)).toBeCloseTo(2.718,3); });
  it('round(1.41421,4)~1.4142', () => { expect(roundPrice(1.41421,4)).toBeCloseTo(1.4142,4); });
  it('round(0.1,2)~0.1', () => { expect(roundPrice(0.1,2)).toBeCloseTo(0.1,2); });
  it('round(0.9999,3)~1', () => { expect(roundPrice(0.9999,3)).toBeCloseTo(1,3); });
  it('round(100,4)~100', () => { expect(roundPrice(100,4)).toBeCloseTo(100,4); });
  it('round(0.12345,4)~0.1235', () => { expect(roundPrice(0.12345,4)).toBeCloseTo(0.1235,4); });
  it('round(50.555,2)~50.56', () => { expect(roundPrice(50.555,2)).toBeCloseTo(50.56,2); });
  it('round(0,2)~0', () => { expect(roundPrice(0,2)).toBeCloseTo(0,2); });
  it('round(999.9994,3)~999.999', () => { expect(roundPrice(999.9994,3)).toBeCloseTo(999.999,3); });
