describe('Integration end-to-end', () => {
  it('enterprise flat', () => { const r = makeRule('e1','E1','flat',1000); expect(calculateQuote([r], { e1: 10 }).total).toBe(10000); });
  it('enterprise+20%VAT', () => { const r = withTax(makeRule('e2','E2','flat',1000), 20); expect(calculateQuote([r], { e2: 5 }).total).toBeCloseTo(6000); });
  it('volume+15%disc+20%tax', () => { const r = withTax(withDiscount(volumeRule(), { type: 'percentage', value: 15 }), 20); const q = calculateQuote([r], { r2: 20 }); const s=1600, d=s*0.15, t=(s-d)*0.2; expect(q.total).toBeCloseTo(s-d+t); });
  it('tiered+fixed disc', () => { const trs: PriceTier[] = [{ minQty:1, maxQty:5, unitPrice:200 }, { minQty:6, unitPrice:150 }]; const r = withDiscount(withTiers(makeRule('t1','T','tiered',200), trs), { type: 'fixed', value: 50 }); const q = calculateQuote([r], { t1: 8 }); expect(q.subtotal).toBeCloseTo(5*200+3*150); expect(q.totalDiscount).toBeCloseTo(50); });
  it('multi-rule flat+vol+pu', () => { const r1 = withTax(makeRule('a','A','flat',500), 20); const q = calculateQuote([r1, volumeRule(), perUnitRule()], { a: 2, r2: 15, r4: 10 }); expect(q.items).toHaveLength(3); expect(q.subtotal).toBeCloseTo(2700); });
  it('disc minQty not met', () => { const r = withDiscount(flatRule(), { type: 'percentage', value: 20, minQty: 10 }); const q = calculateQuote([r], { r1: 5 }); expect(q.totalDiscount).toBe(0); expect(q.total).toBe(1000); });
  it('disc minQty met', () => { const r = withDiscount(flatRule(), { type: 'percentage', value: 20, minQty: 10 }); const q = calculateQuote([r], { r1: 10 }); expect(q.totalDiscount).toBeCloseTo(400); expect(q.total).toBeCloseTo(1600); });
  it('stacked pct+fixed', () => { const r = withDiscount(withDiscount(flatRule(), { type: 'percentage', value: 10 }), { type: 'fixed', value: 50 }); const q = calculateQuote([r], { r1: 3 }); expect(q.total).toBeGreaterThanOrEqual(0); });
  it('zero price rule', () => { const r = makeRule('z','Z','flat',0); expect(calculateQuote([r], { z: 100 }).total).toBe(0); });
  it('large qty 1M', () => { const r = makeRule('b','B','flat',1); expect(calculateQuote([r], { b: 1000000 }).subtotal).toBe(1000000); });
  it('per_unit like flat', () => { const q = calculateQuote([perUnitRule()], { r4: 4 }); expect(q.subtotal).toBe(200); expect(q.currency).toBe('USD'); });
  it('tax only total>subtotal', () => { const r = withTax(makeRule('t','T','flat',100), 20); expect(calculateQuote([r], { t: 1 }).total).toBeCloseTo(120); });
  it('full discount total=0', () => { const r = withDiscount(makeRule('f','F','flat',100), { type: 'fixed', value: 10000 }); const q = calculateQuote([r], { f: 1 }); expect(q.total).toBe(0); });
  it('only zero-qty rules empty', () => { const q = calculateQuote([makeRule('a','A','flat',100), makeRule('b','B','flat',200)], { a: 0, b: 0 }); expect(q.items).toHaveLength(0); expect(q.total).toBe(0); });
  it('ruleIds correct', () => { const q = calculateQuote([makeRule('al','Al','flat',100), makeRule('be','Be','flat',200)], { al: 1, be: 2 }); expect(q.items.map(i => i.ruleId)).toContain('al'); expect(q.items.map(i => i.ruleId)).toContain('be'); });
});
